            }
            is StreamingNotSupported -> wire.writeI32(7)
            is NotLoaded -> wire.writeI32(8)
            is ConfigError -> {
                wire.writeI32(9)
                wire.writeString(message)
            }
            is NetworkError -> {
                wire.writeI32(10)
                wire.writeString(message)
            }
            is Offline -> {
                wire.writeI32(11)
                wire.writeString(message)
            }
            is IoError -> {
                wire.writeI32(12)
                wire.writeString(message)
            }
            is CacheError -> {
                wire.writeI32(13)
                wire.writeString(message)
            }
            is PipelineError -> {
                wire.writeI32(14)
                wire.writeString(message)
            }
            is CircuitOpen -> {
                wire.writeI32(15)
                wire.writeString(message)
            }
            is RateLimited -> {
                wire.writeI32(16)
                wire.writeU64(retryAfterSecs)
            }
            is Timeout -> {
                wire.writeI32(17)
                wire.writeU64(timeoutMs)
            }
        }
    }
}

sealed class XybridEnvelopeKind {

    data class Text(val text: String) : XybridEnvelopeKind()

    data class Audio(val bytes: ByteArray) : XybridEnvelopeKind()

    data class Embedding(val values: FloatArray) : XybridEnvelopeKind()

    companion object {
        fun decode(reader: WireReader): XybridEnvelopeKind {
            val tag = reader.readI32()
            return when (tag) {
                0 -> {
                    Text(
                        reader.readString()
                    )
                }
                1 -> {
                    Audio(
                        reader.readBytes()
                    )
                }
                2 -> {
                    Embedding(
                        reader.readFloatArray()
                    )
                }
                else -> throw FfiException(-1, "Unknown XybridEnvelopeKind tag: $tag")
            }
        }
    }

    fun wireEncodedSize(): Int = 4 + when (this) {
        is Text -> (4 + Utf8Codec.maxBytes(text))
        is Audio -> (4 + bytes.size)
        is Embedding -> (4 + values.size * 4)
    }

    fun wireEncodeTo(wire: WireWriter) {
        when (this) {
            is Text -> {
                wire.writeI32(0)
                wire.writeString(text)
            }
            is Audio -> {
                wire.writeI32(1)
                wire.writePrimitiveList(bytes)
            }
            is Embedding -> {
                wire.writeI32(2)
                wire.writePrimitiveList(values)
            }
        }
    }
}

enum class XybridMessageRole(val value: Int) {
    SYSTEM(0),
    USER(1),
    ASSISTANT(2);

    companion object {
        fun fromValue(value: Int): XybridMessageRole = entries.first { it.value == value }
        fun fromWireTag(tag: Int): XybridMessageRole = entries.getOrElse(tag) {
            throw FfiException(-1, "Unknown XybridMessageRole wire tag: $tag")
