/**
 * Single metadata key/value entry. BoltFFI doesn't auto-derive
 * `WireEncode` for `HashMap<String, String>`, so we expose metadata as
 * `Vec<XybridMetadataEntry>`. The conversion back to `HashMap` happens
 * at the facade boundary inside [`XybridEnvelope::into`].
 */
data class XybridMetadataEntry(
    val key: String,
    val `value`: String
) {
    companion object {
        fun decode(reader: WireReader): XybridMetadataEntry = XybridMetadataEntry(
            reader.readString(),
            reader.readString()
        )
    }
    fun wireEncodedSize(): Int =
        (4 + Utf8Codec.maxBytes(key)) +
        (4 + Utf8Codec.maxBytes(`value`))

    fun wireEncodeTo(wire: WireWriter) {
        wire.writeString(key)
        wire.writeString(`value`)
    }
}

data class XybridEnvelope(
    val kind: XybridEnvelopeKind,
    val metadata: List<XybridMetadataEntry>
) {
    companion object {
        fun decode(reader: WireReader): XybridEnvelope = XybridEnvelope(
            XybridEnvelopeKind.decode(reader),
            reader.readList { XybridMetadataEntry.decode(reader) }
        )
    }
    fun wireEncodedSize(): Int =
        kind.wireEncodedSize() +
        (4 + metadata.sumOf { item -> item.wireEncodedSize() })

    fun wireEncodeTo(wire: WireWriter) {
        kind.wireEncodeTo(wire)
        wire.writeU32(metadata.size.toUInt()); metadata.forEach { item -> item.wireEncodeTo(wire) }
    }
}

data class XybridGenerationConfig(
    val maxTokens: UInt? = null,
    val temperature: Float? = null,
    val topP: Float? = null,
    val minP: Float? = null,
    val topK: UInt? = null,
    val repetitionPenalty: Float? = null,
    val stopSequences: List<String>
) {
    companion object {
        fun decode(reader: WireReader): XybridGenerationConfig = XybridGenerationConfig(
            reader.readOptional { reader.readU32() },
            reader.readOptional { reader.readF32() },
            reader.readOptional { reader.readF32() },
            reader.readOptional { reader.readF32() },
            reader.readOptional { reader.readU32() },
            reader.readOptional { reader.readF32() },
            reader.readList { reader.readString() }
        )
    }
    fun wireEncodedSize(): Int =
        (maxTokens?.let { v -> 1 + 4 } ?: 1.toInt()) +
        (temperature?.let { v -> 1 + 4 } ?: 1.toInt()) +
        (topP?.let { v -> 1 + 4 } ?: 1.toInt()) +
        (minP?.let { v -> 1 + 4 } ?: 1.toInt()) +
        (topK?.let { v -> 1 + 4 } ?: 1.toInt()) +
        (repetitionPenalty?.let { v -> 1 + 4 } ?: 1.toInt()) +
        (4 + stopSequences.sumOf { item -> (4 + Utf8Codec.maxBytes(item)) })

    fun wireEncodeTo(wire: WireWriter) {
        maxTokens?.let { v -> wire.writeU8(1u); wire.writeU32(v) } ?: wire.writeU8(0u)
        temperature?.let { v -> wire.writeU8(1u); wire.writeF32(v) } ?: wire.writeU8(0u)
        topP?.let { v -> wire.writeU8(1u); wire.writeF32(v) } ?: wire.writeU8(0u)
        minP?.let { v -> wire.writeU8(1u); wire.writeF32(v) } ?: wire.writeU8(0u)
        topK?.let { v -> wire.writeU8(1u); wire.writeU32(v) } ?: wire.writeU8(0u)
        repetitionPenalty?.let { v -> wire.writeU8(1u); wire.writeF32(v) } ?: wire.writeU8(0u)
        wire.writeU32(stopSequences.size.toUInt()); stopSequences.forEach { item -> wire.writeString(item) }
    }
}

data class XybridRunOptions(
    val generationConfig: XybridGenerationConfig? = null,
    val abortOn: List<XybridAbortSignal>,
    val fallbackToCloud: Boolean,
    val maxGraceTokens: UInt,
    val correlationId: String? = null
) {
    companion object {
        fun decode(reader: WireReader): XybridRunOptions = XybridRunOptions(
            reader.readOptional { XybridGenerationConfig.decode(reader) },
            reader.readList { XybridAbortSignal.decode(reader) },
            reader.readBool(),
            reader.readU32(),
            reader.readOptional { reader.readString() }
        )
    }
    fun wireEncodedSize(): Int =
        (generationConfig?.let { v -> 1 + v.wireEncodedSize() } ?: 1.toInt()) +
        (4 + abortOn.size * 4) +
        1 +
        4 +
        (correlationId?.let { v -> 1 + (4 + Utf8Codec.maxBytes(v)) } ?: 1.toInt())

    fun wireEncodeTo(wire: WireWriter) {
        generationConfig?.let { v -> wire.writeU8(1u); v.wireEncodeTo(wire) } ?: wire.writeU8(0u)
        wire.writeU32(abortOn.size.toUInt()); abortOn.forEach { item -> item.wireEncodeTo(wire) }
        wire.writeBool(fallbackToCloud)
        wire.writeU32(maxGraceTokens)
        correlationId?.let { v -> wire.writeU8(1u); wire.writeString(v) } ?: wire.writeU8(0u)
    }
}

