    }
}

data class XybridInferenceMetrics(
    val totalMs: UInt,
    val ttftMs: UInt? = null,
    val tokensPerSecond: Float? = null,
    val prefillTps: Float? = null,
    val decodeTps: Float? = null,
    val tokensOut: UInt? = null,
    val stageLatenciesMs: List<XybridStageLatency>
) {
    companion object {
        fun decode(reader: WireReader): XybridInferenceMetrics = XybridInferenceMetrics(
            reader.readU32(),
            reader.readOptional { reader.readU32() },
            reader.readOptional { reader.readF32() },
            reader.readOptional { reader.readF32() },
            reader.readOptional { reader.readF32() },
            reader.readOptional { reader.readU32() },
            reader.readList { XybridStageLatency.decode(reader) }
        )
    }
    fun wireEncodedSize(): Int =
        4 +
        (ttftMs?.let { v -> 1 + 4 } ?: 1.toInt()) +
        (tokensPerSecond?.let { v -> 1 + 4 } ?: 1.toInt()) +
        (prefillTps?.let { v -> 1 + 4 } ?: 1.toInt()) +
        (decodeTps?.let { v -> 1 + 4 } ?: 1.toInt()) +
        (tokensOut?.let { v -> 1 + 4 } ?: 1.toInt()) +
        (4 + stageLatenciesMs.sumOf { item -> item.wireEncodedSize() })

    fun wireEncodeTo(wire: WireWriter) {
        wire.writeU32(totalMs)
        ttftMs?.let { v -> wire.writeU8(1u); wire.writeU32(v) } ?: wire.writeU8(0u)
        tokensPerSecond?.let { v -> wire.writeU8(1u); wire.writeF32(v) } ?: wire.writeU8(0u)
        prefillTps?.let { v -> wire.writeU8(1u); wire.writeF32(v) } ?: wire.writeU8(0u)
        decodeTps?.let { v -> wire.writeU8(1u); wire.writeF32(v) } ?: wire.writeU8(0u)
        tokensOut?.let { v -> wire.writeU8(1u); wire.writeU32(v) } ?: wire.writeU8(0u)
        wire.writeU32(stageLatenciesMs.size.toUInt()); stageLatenciesMs.forEach { item -> item.wireEncodeTo(wire) }
    }
}

/**
 * Inference output. Named `XybridResult` (not `XybridInferenceResult`)
 * to match the existing uniffi-generated Kotlin/Swift name — the iOS
 * example references `XybridResult` directly.
 */
data class XybridResult(
    val envelope: XybridEnvelope,
    val outputType: XybridOutputType,
    val modelId: String,
    val latencyMs: UInt,
    val metrics: XybridInferenceMetrics
) {
    companion object {
        fun decode(reader: WireReader): XybridResult = XybridResult(
            XybridEnvelope.decode(reader),
            XybridOutputType.decode(reader),
            reader.readString(),
            reader.readU32(),
            XybridInferenceMetrics.decode(reader)
        )
    }
    fun wireEncodedSize(): Int =
        envelope.wireEncodedSize() +
        4 +
        (4 + Utf8Codec.maxBytes(modelId)) +
        4 +
        metrics.wireEncodedSize()

    fun wireEncodeTo(wire: WireWriter) {
        envelope.wireEncodeTo(wire)
        outputType.wireEncodeTo(wire)
        wire.writeString(modelId)
        wire.writeU32(latencyMs)
        metrics.wireEncodeTo(wire)
    }
}

